inline constexpr float B2 = -0.0667723045f;

inline float relu(float value) { return std::max(0.0f, value); }

inline float score(const std::array<float, INPUT_DIM>& x)
{
  std::array<float, HIDDEN0> h0{};
  for (std::size_t out = 0; out < HIDDEN0; ++out) {
    float sum = B0[out];
    for (std::size_t in = 0; in < INPUT_DIM; ++in)
      sum += W0[out * INPUT_DIM + in] * x[in];
    h0[out] = relu(sum);
  }

  std::array<float, HIDDEN1> h1{};
  for (std::size_t out = 0; out < HIDDEN1; ++out) {
    float sum = B1[out];
    for (std::size_t in = 0; in < HIDDEN0; ++in)
      sum += W1[out * HIDDEN0 + in] * h0[in];
    h1[out] = relu(sum);
  }

  float sum = B2;
  for (std::size_t in = 0; in < HIDDEN1; ++in)
    sum += W2[in] * h1[in];
  return sum;
}

